// ============================================================
// NODE: Build Creatomate Payload
// Assembles the full Creatomate render source JSON.
// ElevenLabs TTS is handled natively by Creatomate —
// just configure your ElevenLabs API key in Creatomate Settings.
// ============================================================

const data = $input.first().json;
// Use ElevenLabs voice NAME (more reliable than ID in Creatomate)
// Change 'Josh' to your preferred ElevenLabs voice name
const VOICE_ID = ($input.first().json.voice_id || 'Josh').trim();

// Background music (royalty-free — replace with your preferred track)
// Recommended: find a dramatic/suspenseful track from Pixabay or Incompetech
// const BG_MUSIC_URL = 'YOUR_MUSIC_URL_HERE';

const elements = [];
let currentTime = 0;

// Calculate total story duration
const storyDuration = data.scenes.reduce((sum, s) => sum + (s.duration_seconds || 20), 0);
const totalDuration = storyDuration + 10; // +10 for outro

// ── BACKGROUND MUSIC (entire video) ──────────────────────────
// bg-music element removed - add your own URL

// ── SCENES ───────────────────────────────────────────────────
for (let i = 0; i < data.scenes.length; i++) {
  const scene = data.scenes[i];
  const dur = scene.duration_seconds || 20;
  const t = `${currentTime} s`;
  const sceneId = `s${i + 1}`;

  // Background video clip
  elements.push({
    id: `${sceneId}-video`,
    type: 'video',
    source: scene.video_url,
    time: t,
    duration: `${dur} s`,
    fit: 'cover',
    volume: '0%'
  });

  // Subtle dark overlay for caption readability
  elements.push({
    id: `${sceneId}-overlay`,
    type: 'shape',
    shape: 'rect',
    fill_color: 'rgba(0,0,0,0.40)',
    time: t,
    duration: `${dur} s`,
    width: '100%',
    height: '100%'
  });

  // ElevenLabs voiceover (Creatomate calls ElevenLabs directly)
  // Requires: ElevenLabs API key configured in Creatomate Settings > Integrations
  elements.push({
    id: `${sceneId}-voice`,
    type: 'audio',
    provider: 'elevenlabs',
    text: scene.narration,
    voice: 'Josh',
    time: t
  });

  // Caption text (styled like modern storytelling channels)
  elements.push({
    id: `${sceneId}-caption`,
    type: 'text',
    text: (() => { const s = scene.narration.match(/[^.!?]+[.!?]+/); return s ? s[0].trim() : scene.narration.substring(0, 120); })(),
    time: t,
    duration: `${dur} s`,
    x_alignment: '50%',
    y_alignment: '85%',
    width: '88%',
    font_family: 'Montserrat',
    font_weight: '700',
    font_size: '38',
    max_font_size: '38',
    min_font_size: '20',
    fit: 'contain',
    fill_color: '#FFFFFF',
    stroke_color: '#000000',
    stroke_width: '3',
    line_height: '1.4',
    background_color: 'rgba(0,0,0,0.55)',
    background_x_padding: '2%',
    background_y_padding: '1.5%',
    background_border_radius: '6',
    text_clip_start: '0.3 s',
    text_clip_end: `${dur - 0.3} s`
  });

  // Scene number pill (top-left, subtle)
  elements.push({
    id: `${sceneId}-num`,
    type: 'text',
    text: `${i + 1} / ${data.scenes.length}`,
    time: t,
    duration: `${dur} s`,
    x: '3%',
    y: '4%',
    font_family: 'Montserrat',
    font_weight: '500',
    font_size: '18',
    fill_color: 'rgba(255,255,255,0.6)'
  });

  currentTime += dur;
}

// ── OUTRO CARD ───────────────────────────────────────────────
elements.push({
  id: 'outro-bg',
  type: 'shape',
  shape: 'rect',
  fill_color: '#0d0d1a',
  time: `${currentTime} s`,
  duration: '10 s',
  width: '100%',
  height: '100%'
});

elements.push({
  id: 'outro-moral',
  type: 'text',
  text: data.moral_question,
  time: `${currentTime} s`,
  duration: '10 s',
  x_alignment: '50%',
  y_alignment: '42%',
  width: '80%',
  font_family: 'Montserrat',
  font_weight: '700',
  font_size: '44',
  fill_color: '#FFFFFF',
  line_height: '1.3'
});

elements.push({
  id: 'outro-cta',
  type: 'text',
  text: '💬 Drop your thoughts in the comments!',
  time: `${currentTime + 2} s`,
  duration: '8 s',
  x_alignment: '50%',
  y_alignment: '62%',
  width: '80%',
  font_family: 'Montserrat',
  font_weight: '600',
  font_size: '28',
  fill_color: '#FFD700'
});

elements.push({
  id: 'outro-subscribe',
  type: 'text',
  text: '👆 Subscribe for more stories',
  time: `${currentTime + 3} s`,
  duration: '7 s',
  x_alignment: '50%',
  y_alignment: '72%',
  width: '80%',
  font_family: 'Montserrat',
  font_weight: '500',
  font_size: '22',
  fill_color: 'rgba(255,255,255,0.75)'
});

const creatomatePayload = {
  output_format: 'mp4',
  width: 1920,
  height: 1080,
  fps: 30,
  elements: elements
};

const renderRequestStr = JSON.stringify([{ source: creatomatePayload }]);
const renderRequest = [{ source: creatomatePayload }];

return [{
  json: {
    topic: data.topic,
    title: data.title,
    description: data.description,
    tags: data.tags,
    tags_string: Array.isArray(data.tags) ? data.tags.join(',') : data.tags,
    thumbnail_text: data.thumbnail_text,
    moral_question: data.moral_question,
    total_duration_seconds: totalDuration,
    creatomate_payload: creatomatePayload,
    render_request_str: renderRequestStr,
    render_request: renderRequest
  }
}];

// ============================================================
// NODE: Attach Metadata
// Bridges the binary download with the video metadata.
// Passes both JSON metadata and binary video to YouTube node.
// ============================================================

const binary = $input.first().binary;
const meta = $('Poll Render Status').first().json;

if (!binary || !binary.data) {
  throw new Error('No binary video data found from download step.');
}

return [{
  json: {
    title: meta.title,
    description: meta.description,
    tags_string: meta.tags_string || 'betrayal,revenge,story',
    topic: meta.topic,
    moral_question: meta.moral_question
  },
  binary: {
    data: binary.data
  }
}];

// ============================================================
// NODE: Build Shorts Payload
// Creates a vertical 9:16 Creatomate render using Scene 1 only.
// The hook ends with a CTA directing viewers to the full video.
// ============================================================

const longFormVideoId = $('Upload to YouTube').first().json.id;
const data = $('Fetch Scene Videos').first().json;
const VOICE_ID = $('Fetch Scene Videos').first().json.voice_id;

const hookScene = data.scenes[0];
const hookDuration = Math.min(hookScene.duration_seconds || 20, 50);
const ctaDuration = 8;
const totalDuration = hookDuration + ctaDuration;

const elements = [];

// ── HOOK SCENE (vertical crop of scene 1) ────────────────────
elements.push({
  id: 'hook-video',
  type: 'video',
  source: hookScene.video_url,
  time: '0 s',
  duration: `${hookDuration} s`,
  fit: 'cover',
  volume: '0%'
});

elements.push({
  id: 'hook-overlay',
  type: 'shape',
  shape: 'rect',
  fill_color: 'rgba(0,0,0,0.42)',
  time: '0 s',
  duration: `${hookDuration} s`,
  width: '100%',
  height: '100%'
});

// ElevenLabs voice (Creatomate handles TTS natively)
elements.push({
  id: 'hook-voice',
  type: 'audio',
  provider: 'elevenlabs',
  text: hookScene.narration,
  voice: VOICE_ID,
  time: '0 s'
});

// Caption
elements.push({
  id: 'hook-caption',
  type: 'text',
  text: hookScene.narration,
  time: '0 s',
  duration: `${hookDuration} s`,
  x_alignment: '50%',
  y_alignment: '74%',
  width: '88%',
  font_family: 'Montserrat',
  font_weight: '700',
  font_size: '34',
  fill_color: '#FFFFFF',
  stroke_color: '#000000',
  stroke_width: '2.5',
  line_height: '1.4'
});

// 'STORY CONTINUES' badge fades in at 70% through narration
elements.push({
  id: 'teaser-badge',
  type: 'text',
  text: '🔴 STORY CONTINUES...',
  time: `${(hookDuration * 0.65).toFixed(1)} s`,
  duration: `${(hookDuration * 0.35).toFixed(1)} s`,
  x_alignment: '50%',
  y_alignment: '18%',
  width: '90%',
  font_family: 'Montserrat',
  font_weight: '800',
  font_size: '30',
  fill_color: '#FF3B3B',
  text_clip_start: '0.4 s'
});

// ── CTA CARD ─────────────────────────────────────────────────
elements.push({
  id: 'cta-bg',
  type: 'shape',
  shape: 'rect',
  fill_color: '#0d0d1a',
  time: `${hookDuration} s`,
  duration: `${ctaDuration} s`,
  width: '100%',
  height: '100%'
});

elements.push({
  id: 'cta-main',
  type: 'text',
  text: 'Watch what happens next 👆',
  time: `${hookDuration} s`,
  duration: `${ctaDuration} s`,
  x_alignment: '50%',
  y_alignment: '38%',
  width: '85%',
  font_family: 'Montserrat',
  font_weight: '800',
  font_size: '52',
  fill_color: '#FFFFFF',
  line_height: '1.2'
});

elements.push({
  id: 'cta-sub',
  type: 'text',
  text: 'Full story on channel ⬆️',
  time: `${hookDuration + 1} s`,
  duration: `${ctaDuration - 1} s`,
  x_alignment: '50%',
  y_alignment: '56%',
  width: '85%',
  font_family: 'Montserrat',
  font_weight: '600',
  font_size: '34',
  fill_color: '#FFD700'
});

elements.push({
  id: 'cta-subscribe',
  type: 'text',
  text: '🔔 Subscribe for more stories',
  time: `${hookDuration + 2} s`,
  duration: `${ctaDuration - 2} s`,
  x_alignment: '50%',
  y_alignment: '68%',
  width: '85%',
  font_family: 'Montserrat',
  font_weight: '500',
  font_size: '26',
  fill_color: 'rgba(255,255,255,0.75)'
});

// ── SHORTS METADATA ──────────────────────────────────────────
const fullTitle = $('Fetch Scene Videos').first().json.title || '';
// Keep under 60 chars, must contain #Shorts for YouTube to classify it
const rawShortTitle = fullTitle.length > 48
  ? fullTitle.substring(0, 45) + '...'
  : fullTitle;
const shortsTitle = `${rawShortTitle} #Shorts`;

const shortsDesc = [
  hookScene.narration.substring(0, 120) + '...',
  '',
  `👉 Full story: https://youtu.be/${longFormVideoId}`,
  '',
  '#Shorts #betrayal #revenge #story #aita #drama #ofw'
].join('\n');

const shortsPayload = {
  output_format: 'mp4',
  width: 1080,
  height: 1920,
  fps: 30,
  elements: elements
};

const shortsRenderRequestStr = JSON.stringify([{ source: shortsPayload }]);

return [{
  json: {
    shorts_payload: shortsPayload,
    shorts_title: shortsTitle,
    shorts_description: shortsDesc,
    shorts_tags: 'shorts,betrayal,revenge,aita,drama,story time,youtube shorts,ofw',
    long_form_video_id: longFormVideoId,
    topic: data.topic,
    full_title: fullTitle,
    shorts_render_request_str: shortsRenderRequestStr
  }
}];

// ============================================================
// NODE: Attach Shorts Metadata
// Bridges the Shorts binary download with its metadata.
// ============================================================

const binary = $input.first().binary;
const meta = $('Poll Shorts Status').first().json;

if (!binary || !binary.data) {
  throw new Error('No binary data found for Shorts video.');
}

return [{
  json: {
    shorts_title: meta.shorts_title,
    shorts_description: meta.shorts_description,
    shorts_tags: meta.shorts_tags || 'shorts,betrayal,revenge,story',
    long_form_video_id: meta.long_form_video_id,
    topic: meta.topic,
    full_title: meta.full_title
  },
  binary: { data: binary.data }
}];

