const topic = $input.first().json.Topic;
if (!topic) throw new Error('No topic found.');

return [{
  json: {
    topic,
    request_body: {
      model: 'claude-sonnet-4-6',
      max_tokens: 2500,
      system: "You are a professional YouTube scriptwriter for a faceless channel called Betrayal & Revenge Stories. Your audience is both American and Filipino. You write emotionally gripping suspenseful anonymous first-person stories. RETURN ONLY a valid JSON object no markdown no backticks no explanation. Use this exact structure: { \"title\": \"YouTube title max 60 chars emotional power words\", \"description\": \"150-200 words hook first sentence story summary moral question end with #betrayal #revenge #story #aita #drama #ofw\", \"tags\": [\"betrayal\",\"revenge story\",\"aita\",\"reddit story\",\"relationship drama\",\"story time\",\"ofw story\"], \"thumbnail_text\": \"5-7 dramatic words for thumbnail\", \"scenes\": [ { \"scene_number\": 1, \"narration\": \"2-4 sentences first-person conversational builds suspense never use character names\", \"visual_keyword\": \"3-word Pexels search keyword specific emotions and settings\", \"duration_seconds\": 20 } ], \"moral_question\": \"One punchy question for comment engagement\" } STORY RULES: Exactly 9 scenes. Scene 1 hook start with most shocking moment in medias res. Scenes 2-4 background who betrayed who and why. Scenes 5-7 confrontation and escalation. Scenes 8-9 resolution and aftermath end with moral ambiguity. Stories must feel authentic to both US and Filipino culture.",
      messages: [{ role: 'user', content: 'Write a betrayal and revenge YouTube video script about: ' + topic }]
    }
  }
}];

const https = require('https');

const data = $input.first().json;
const PEXELS_API_KEY = ($('API Config').first().json.PEXELS_API_KEY || '').trim();
const VOICE_ID = ($('API Config').first().json.ELEVENLABS_VOICE_ID || '').trim();

// Creatomate's own demo assets — 100% confirmed accessible from Creatomate's servers
// Google CDN videos (commondatastorage) are inconsistent — removed
// Upgrade path: subscribe to Storyblocks or host your own videos on S3/Cloudflare R2
const GUARANTEED_FALLBACKS = [
  'https://creatomate-static.s3.amazonaws.com/demo/video1.mp4',
  'https://creatomate-static.s3.amazonaws.com/demo/video2.mp4',
  'https://creatomate-static.s3.amazonaws.com/demo/video3.mp4',
  'https://creatomate-static.s3.amazonaws.com/demo/video4.mp4',
  'https://creatomate-static.s3.amazonaws.com/demo/video5.mp4'
];

// Search Pexels and try to find a Vimeo-hosted URL (accessible from any server)
// Vimeo-external URLs from Pexels look like: https://player.vimeo.com/external/...
// These bypass Pexels hotlink protection
async function searchPexelsVimeoUrl(keyword) {
  return new Promise((resolve) => {
    const req = https.request({
      hostname: 'api.pexels.com',
      path: '/videos/search?query=' + encodeURIComponent(keyword) + '&per_page=15&orientation=landscape&size=medium',
      headers: { 'Authorization': PEXELS_API_KEY }
    }, (res) => {
      let body = '';
      res.on('data', c => body += c);
      res.on('end', () => {
        try {
          const result = JSON.parse(body);
          for (const video of (result.videos || [])) {
            for (const file of (video.video_files || [])) {
              // Vimeo-external URLs work with Creatomate
              if (file.link && file.link.includes('player.vimeo.com')) {
                if (file.width && file.width <= 1280) {
                  resolve(file.link);
                  return;
                }
              }
            }
          }
          // Second pass: any Vimeo URL regardless of quality
          for (const video of (result.videos || [])) {
            for (const file of (video.video_files || [])) {
              if (file.link && file.link.includes('player.vimeo.com')) {
                resolve(file.link);
                return;
              }
            }
          }
          resolve(null);
        } catch(e) { resolve(null); }
      });
    });
    req.on('error', () => resolve(null));
    req.end();
  });
}

const scenesWithVideos = [];

for (let i = 0; i < data.scenes.length; i++) {
  const scene = data.scenes[i];
  let videoUrl = GUARANTEED_FALLBACKS[i % GUARANTEED_FALLBACKS.length];

  if (PEXELS_API_KEY) {
    try {
      const vimeoUrl = await searchPexelsVimeoUrl(scene.visual_keyword);
      if (vimeoUrl) {
        videoUrl = vimeoUrl;
      }
    } catch(e) {}
  }

  scenesWithVideos.push({ ...scene, video_url: videoUrl });

  // Rate limit protection (200 req/hour on free Pexels)
  if (i < data.scenes.length - 1) {
    await new Promise(r => setTimeout(r, 400));
  }
}

return [{ json: { ...data, scenes: scenesWithVideos, voice_id: VOICE_ID } }];

const https = require('https');

const data = $input.first().json;
const apiKey = ($('API Config').first().json.CREATOMATE_API_KEY || '').trim();

if (!data.creatomate_payload) {
  throw new Error('creatomate_payload missing. Run Execute previous nodes first.');
}

// ✅ FIXED: Send a plain OBJECT { source: {...} }
// NOT an array [{ source: {...} }]
const requestBody = JSON.stringify({ source: data.creatomate_payload });

const bodyBuffer = Buffer.from(requestBody, 'utf8');

const result = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.creatomate.com',
    path: '/v1/renders',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer ' + apiKey,
      'Content-Length': bodyBuffer.length
    }
  }, (res) => {
    let body = '';
    res.on('data', chunk => body += chunk);
    res.on('end', () => resolve({ statusCode: res.statusCode, body }));
  });
  req.on('error', reject);
  req.write(bodyBuffer);
  req.end();
});

if (result.statusCode >= 400) {
  throw new Error('Creatomate ' + result.statusCode + ': ' + result.body);
}

const renderData = JSON.parse(result.body);
// Response is an array of render objects
const render = Array.isArray(renderData) ? renderData[0] : renderData;
if (!render.id) throw new Error('No render ID: ' + result.body.substring(0, 200));

return [{
  json: {
    render_id: render.id,
    render_status: render.status,
    topic: data.topic,
    title: data.title,
    description: data.description,
    tags: data.tags,
    tags_string: data.tags_string,
    thumbnail_text: data.thumbnail_text,
    moral_question: data.moral_question
  }
}];

const https = require('https');

// Get render_id from Submit Render node directly — bypasses Google Sheets data loss
const renderId = $('Extract Render Data').first().json.render_id;
const apiKey = ($('API Config').first().json.CREATOMATE_API_KEY || '').trim();
const meta = $('Extract Render Data').first().json;

if (!renderId) {
  throw new Error('render_id missing. Check Extract Render Data node output.');
}

const result = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.creatomate.com',
    path: '/v1/renders/' + renderId,
    method: 'GET',
    headers: { 'Authorization': 'Bearer ' + apiKey }
  }, (res) => {
    let body = '';
    res.on('data', chunk => body += chunk);
    res.on('end', () => resolve({ statusCode: res.statusCode, body }));
  });
  req.on('error', reject);
  req.end();
});

if (result.statusCode >= 400) {
  throw new Error('Creatomate poll ' + result.statusCode + ': ' + result.body);
}

const render = JSON.parse(result.body);

return [{
  json: {
    ...meta,
    render_status: render.status,
    render_url: render.url || null,
    render_error: render.error_message || null
  }
}];

// Pass through but stop if render permanently failed
const item = $input.first().json;
if (item.render_status === 'failed') {
  throw new Error('Render failed: ' + (item.render_error || 'Unknown'));
}
return $input.all();

const https = require('https');

const data = $input.first().json;
const apiKey = ($('API Config').first().json.CREATOMATE_API_KEY || '').trim();

if (!data.shorts_payload) {
  throw new Error('shorts_payload missing from input.');
}

// ✅ FIXED: Plain object, not array
const requestBody = JSON.stringify({ source: data.shorts_payload });
const bodyBuffer = Buffer.from(requestBody, 'utf8');

const result = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.creatomate.com',
    path: '/v1/renders',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer ' + apiKey,
      'Content-Length': bodyBuffer.length
    }
  }, (res) => {
    let body = '';
    res.on('data', chunk => body += chunk);
    res.on('end', () => resolve({ statusCode: res.statusCode, body }));
  });
  req.on('error', reject);
  req.write(bodyBuffer);
  req.end();
});

if (result.statusCode >= 400) {
  throw new Error('Creatomate Shorts ' + result.statusCode + ': ' + result.body);
}

const renderData = JSON.parse(result.body);
const render = Array.isArray(renderData) ? renderData[0] : renderData;
if (!render.id) throw new Error('No shorts render ID: ' + result.body.substring(0, 200));

return [{
  json: {
    ...data,
    shorts_render_id: render.id,
    shorts_render_status: render.status
  }
}];

const https = require('https');

const shortsRenderId = $('Extract Shorts Render').first().json.shorts_render_id;
const apiKey = ($('API Config').first().json.CREATOMATE_API_KEY || '').trim();
const meta = $('Extract Shorts Render').first().json;

if (!shortsRenderId) {
  throw new Error('shorts_render_id missing. Check Extract Shorts Render node output.');
}

const result = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.creatomate.com',
    path: '/v1/renders/' + shortsRenderId,
    method: 'GET',
    headers: { 'Authorization': 'Bearer ' + apiKey }
  }, (res) => {
    let body = '';
    res.on('data', chunk => body += chunk);
    res.on('end', () => resolve({ statusCode: res.statusCode, body }));
  });
  req.on('error', reject);
  req.end();
});

if (result.statusCode >= 400) {
  throw new Error('Creatomate shorts poll ' + result.statusCode + ': ' + result.body);
}

const render = JSON.parse(result.body);

return [{
  json: {
    ...meta,
    shorts_render_status: render.status,
    shorts_render_url: render.url || null
  }
}];

const raw = $input.first().json;
const topic = $('Prepare Claude Request').first().json.topic;

if (!raw.content || !raw.content[0]) {
  throw new Error('Unexpected Claude response: ' + JSON.stringify(raw).substring(0, 200));
}

const rawText = raw.content[0].text.trim();

const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/, '')
  .trim();

let script;
try {
  script = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse Claude JSON: ' + e.message + ' | Raw: ' + cleaned.substring(0, 300));
}

if (!script.scenes || !Array.isArray(script.scenes)) {
  throw new Error('Invalid script: missing scenes array');
}

script.scenes = script.scenes.slice(0, 9);

return [{
  json: {
    topic,
    title: script.title,
    description: script.description,
    tags: script.tags || ['betrayal','revenge','story'],
    tags_string: (script.tags || ['betrayal','revenge','story']).join(','),
    thumbnail_text: script.thumbnail_text || script.title.substring(0, 40),
    moral_question: script.moral_question || 'Was this the right thing to do?',
    scenes: script.scenes,
    total_scenes: script.scenes.length
  }
}];
